INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常推荐，博物馆值得看看', '非常推荐，博物馆值得看看', '2025-01-30', 5, '[''整体满意度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235h12000i6bi01d1F66_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000i6a56gy63A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000i6biq6s3D6F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '二次入住，这次时间比较宽裕，更好体验酒店服务和设施，前台betty专业，服务热情', '二次入住，这次时间比较宽裕，更好体验酒店服务和设施，前台betty专业，服务热情，客服服务及时热情，餐厅也好吃。', '2025-03-29', 5, '[''前台服务'', ''客房服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233m12000jecsol8C24A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000jeca3s17FFA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂装修豪华，服务到位，非常舒适', '大堂装修豪华，服务到位，非常舒适', '2025-02-10', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235112000ifpqrjvE842_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231x12000ifpqxhy4FAF_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231d12000ifpqv1a08F5_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来广州首选花园酒店，住过好几次了还是非常满意！工作人员热情有礼，感谢Cecili', '来广州首选花园酒店，住过好几次了还是非常满意！工作人员热情有礼，感谢Cecilia和Gillian，看到我们带小孩就给我们免费升级了房间～房间干净整洁，早餐品种比较丰富，味道很不错的。', '2024-08-30', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236b12000faxc77w62A4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000faxaxonC3BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000faxd2jj4E46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000faxd2jl8132_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为广州本地人，我偶尔住酒店换换心情，常住的是MO，这次换了花园酒店，很是惊喜。', '作为广州本地人，我偶尔住酒店换换心情，常住的是MO，这次换了花园酒店，很是惊喜。花园是广州最老牌的五星酒店，改革开放后算是广州地标了，本地人无人不知，那时是外宾住的，当时还没有四季瑰丽MO。十年前，装修前我也住过，体验也不错。这次是装修后，升级了红棉套房，房间大，设计合理，床垫舒适，按这个价格来说，性价比极高了。服务方面，所有服务人员都很热情，有笑容，尤其多了很多印度服务生，那态度更好，笑得也灿烂。基本上，客人的要求有求必应，服务专业周到，我离开酒店遗漏钱包在保险柜，也马上联系，妥善处理，可以体会出来是正宗五星酒店的服务水平。早餐，4个餐厅，吃的也好。总体来说，这是家有品位，有品质，有文化底蕴的五星酒店，值得！', '2024-08-17', 5, '[''整体满意度'', ''性价比'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231d12000f5lrv509B8F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包', '在广州居住很多年，17年离开后每年也一定会回来小住一段时间，期间住过很多酒店，包括久负盛名的四季、丽思卡尔顿、白天鹅等等，这次花园酒店给我的感受是最棒的，酒店建成虽然年代久了，但是各种细节一点也不马虎，房间灯光的设计恰到好处，不亮也不暗；家具布置使用方便舒适；早餐的每个餐桌都有鲜花；每一个喷泉都干净清洁且保持流水状态；恰逢周一，我还碰到了酒店博物馆闭馆日在按惯例清洁水池，以上所有这些细节都看的出酒店的管理和运作非常良好。酒店四楼的博物馆完全超出了我的想象，开始以为会是一个简单的展示，但其实非常专业，很值得一看。餐厅出品也非常棒，在荔湾亭吃了两顿饭，出品很不错，服务人员会主动告诉我怎么点餐最划算；泳池水干净清澈，配备的救生人员也足够数量，各个角度都能覆盖；酒店大堂富丽堂皇又有底蕴；瀑布和花园的亭台楼阁完美的体现着岭南的风貌。给我办理入住的吴经理，看到我定了前后日期相连的两个订单，一个是普通的花园房，一个是粤韵房，主动帮我把前两天的房间也给升级成了粤韵房，避免我要更换房间的麻烦；入住第二天咨询前台人员，准备购买酒店早餐，前台的Ann小姐特别Nice,见我就是一个人带个五岁小朋友，直接免了早餐，更把后面两天要来会合的孩子爸爸早餐也给送了；离开前一天下午到酒店行政酒廊看看风景喝点东西，行政酒廊的每一位小姐姐都非常亲切周到，主动提供各种信息和服务，其中一位Kitty小姐姐贴心热情的邀请我们第二天一早来酒廊用早餐。入住期间提出的所有要求都及时响应，每天都会送上水果和小食，房间打扫及时卫生，遇到的每一位服务人员都热情耐心，感谢酒店所有人美声甜的小姐姐们和友善贴心的帅哥们，以及所有一丝不苟对品质有所坚持的管理者们，为你们的用心送上大大的赞，也希望能够保留这样的底蕴到地久天长。以后来广州不会再更换酒店了，一定是花园酒店！', '2024-08-13', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232s12000f3zjl9u3DDE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000f3zilnn631F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000f3zkz5140C0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '原本对这家建造较早的酒店存有刻板印象，所以只作为备选，还订错了入住日期，在酒店前', '原本对这家建造较早的酒店存有刻板印象，所以只作为备选，还订错了入住日期，在酒店前厅部郑经理热情耐心的远程协调下，不仅调整好日期，还获得了小惊喜。入住后，被酒店红红火火的年味、历史与现代的完美融合和小帅小美们暖暖的服务惊到了。2025的广州春节，为我们整个团队的小伙伴带来了开年好运！', '2025-02-05', 3, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234s12000ibffb96112D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '相比卓美亚，这里完胜。首先这里窗外毫无景色，我相信选择老牌五星酒店不是为了窗外景', '相比卓美亚，这里完胜。首先这里窗外毫无景色，我相信选择老牌五星酒店不是为了窗外景色来的，一进酒店大堂所有人都会被那幅红楼梦黄金雕刻所吸引，大堂明亮宽敞，前台办理入住有条不紊，有空房直接升级，赞。大堂礼宾服务周到，人多的时候始终有服务员帮客人按电梯，服务质量和人员完胜卓美亚十条街。房间都重新翻新过，古朴典雅、并且是套房你也敢相信，房间隔音还算不错，只是门不怎么隔音，洗漱用品也升级过了，床品也不错。楼下四家米其林餐厅实在是没机会品尝，下一次一定尝试，酒店内有的园林很不错，瀑布很高，很适合吃完饭在酒店里逛一逛。卫生我唯一没给满分的原因就是泳池的水有些浑浊，不如卓美亚的，不过其他几乎都是优点了，尤其很多航司都在这里过夜，看到阿航的姑娘们的确很美。还会再来', '2024-08-15', 4, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230k12000f4u6p3u8101_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235t12000f4uf75z1AD8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000f4uhkm7E654_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000f4ugjx341B4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '??酒店性价比很高，房间也非常干净，服务也很周到，酒店也特别有氛围感，特别有城市', '??酒店性价比很高，房间也非常干净，服务也很周到，酒店也特别有氛围感，特别有城市花园和小世外桃源的感觉，不愧是花园酒店～下次还会再选择这里的??', '2024-09-17', 5, '[''性价比'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230a12000fm11qurA336_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000fm141j609C7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232c12000fm12xs47164_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一如既往的好，喜欢。床特别舒服。', '一如既往的好，喜欢。床特别舒服。', '2024-12-25', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235612000heo2gvdA039_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000heobb4lAABE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000heo1cko8792_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来广州出差选择最多的酒店之一，设施设备维护妥当，床品的质量也不错，不足的地方在于', '来广州出差选择最多的酒店之一，设施设备维护妥当，床品的质量也不错，不足的地方在于健身房的设备老旧，只有部分器械做了更换，另外房间的淋浴房水压有点小。', '2024-09-08', 4, '[''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231c12000fgi9hls2CF7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店入住体验极佳，设施先进，服务细致，卫生干净，环境宁静舒适，每个细节都', '广州花园酒店入住体验极佳，设施先进，服务细致，卫生干净，环境宁静舒适，每个细节都彰显高品质，让人印象深刻。', '2024-11-01', 5, '[''整体满意度'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231012000gf9kkzq7121_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000gf9a9sj6DB3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000gfa70ee60D8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是老牌五星酒店，贴心温暖，细致到让你无法想象：酒店有三个早餐厅，第一天是1楼', '不愧是老牌五星酒店，贴心温暖，细致到让你无法想象：酒店有三个早餐厅，第一天是1楼的瀑布餐厅，享受大自然的美妙，第二天是顶楼的旋转餐厅，伏视高空美景，第三天是三楼的精致早茶。美味惊艳。
     楼层服务员：lili每天换这花样送惊喜', '2024-08-01', 5, '[''餐饮设施'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234v12000eyrdteqEBF9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000eyrpa1kA443_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店名不虚传，大堂金碧辉煌，花园漂亮大气，餐饮美味，服务非常贴心，环境优美。', '花园酒店名不虚传，大堂金碧辉煌，花园漂亮大气，餐饮美味，服务非常贴心，环境优美。尤其是30楼行政酒廊的Carrie服务非常周到，对小朋友很有耐心，细心，中文说的非常好?还有Aimee 和Echo美丽大方，热情好客，让客人有宾至如归的感觉，下次来广州还住这里！', '2024-08-19', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q12000f6ih3mc70CF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z12000f6ibrszC5D9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000f6ihx0c953B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000f6iht3vB3F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000f6i2x9z2F2E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000f6ict8k6C0A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000f6icbrxEABA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000f6iekma69CF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000f6i516q18D1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '谢谢，这次会议连着住1周，加上在花园第N次入住，前台Betty给升级。非常好', '谢谢，这次会议连着住1周，加上在花园第N次入住，前台Betty给升级。非常好', '2025-01-05', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230512000hlnuarn2E51_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '选择花园酒店，是一种情怀。', '选择花园酒店，是一种情怀。
20年前，年幼的我第一次来到广州，就在花园酒店，其间的纸醉金迷震撼到我20年不忘。
20年后，我4岁的女儿第一次来广州，也想让她与我拥有同样的记忆。
特别感谢前台的viria小姐姐，大气的为我们升级了房型，红棉房的瀑布景观让这份美好的记忆再上一层楼，我本来只订了一晚，果断原房续住又加了两晚。
这些年国内国外住过很多酒店，但花园酒店会一直在我的推荐清单上。', '2024-07-29', 5, '[''前台服务'', ''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233z12000exo29618647_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231e12000exnuusg2E55_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000exobas7D5A1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次来广州听取老婆意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，太', '这次来广州听取老婆意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，太nice了房间是一厅一房特别的舒适。这次入住真的是我来广州住的最舒服的一次，酒店本身就是一个可以逛和参观的地方，它的底蕴真的是其他酒店无法比拟的。连着续订三晚', '2024-07-28', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234b12000exg82i57B94_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235512000exg2opy42DC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000exfzt0r32D8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '满意的体验，在广州无论自己度假还是接待朋友，都会首选花园酒店，服务，环境，酒店的', '满意的体验，在广州无论自己度假还是接待朋友，都会首选花园酒店，服务，环境，酒店的活动空间都非常好，房间舒适温馨。', '2024-10-07', 5, '[''整体满意度'', ''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232z12000g12q1srD50F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000g12mdpt5C19_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000g12xuf85078_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次入住的房间非常干净，窗外景观不错，位置优越，交通便利，入住体验非常好，前台张', '这次入住的房间非常干净，窗外景观不错，位置优越，交通便利，入住体验非常好，前台张荣荣服务态度也很好，帮忙处理了续住等小事情，周到细心很热情，不错，推荐。', '2024-09-08', 5, '[''整体满意度'', ''卫生状况'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230212000fgfa42nC144_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-