com/images/0231p12000g20i0e3728F_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231s12000g20igybC051_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '真的是很满意的一次入住，从进入酒店开始，每一个服务人员都超级贴心，前台小姐姐热情', '真的是很满意的一次入住，从进入酒店开始，每一个服务人员都超级贴心，前台小姐姐热情的帮我办理了入住，30楼的mignon aimee Carrie 从下午茶开始就热情并贴心的照顾我，服务超级棒????真心感谢????', '2024-06-18', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233l12000eidndpuCA3A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000eidtk266E87_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000eiduiea9D2D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000eidouyf141C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店公共设施装修的很好，但是客房内部装修有点老，服务还是不错的，由于预订时房型没', '酒店公共设施装修的很好，但是客房内部装修有点老，服务还是不错的，由于预订时房型没看清而选错，入住时前台再三提醒确认及时更改。希望酒店能够将客房内部装修再提升下，以后再来还会选择入住。', '2024-06-28', 4, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236u12000elzu52wACED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000elzz8gnDB1B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a12000elzzqu9B489_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：一流。', '设施：一流。
卫生：干净。
环境：古朴典雅。
服务：热情。前台员工对我的态度很好。主动帮我升级了房型。', '2024-09-07', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235q12000fg1ptsuD12A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000fg14z7dF84C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '首先要感谢一下前台的Rebecca,帮我做了房间升级，每次来广州都会选择花园酒店', '首先要感谢一下前台的Rebecca,帮我做了房间升级，每次来广州都会选择花园酒店，虽然酒店是最早一批的五星级酒店，但酒店后期有从新翻修过，整体房间设备都很好，酒店的服务也很好，也要感谢一下行政酒廊Carrie,跟她的伙伴们Deepa和Kanchan，她们整体服务真的很好，让你感觉分宾至如归的感觉，真心推荐给大家！！！', '2024-06-17', 5, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233s224x8vbvo8npE745_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d224x8vbu8e1r42D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f224x8vburw49BAB6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店的地理位置十分优越，紧邻市中心，交通便利，无论是商务出差还是休闲旅游', '广州花园酒店的地理位置十分优越，紧邻市中心，交通便利，无论是商务出差还是休闲旅游，都能轻松抵达城市的各个角落。

步入酒店大堂，大堂的就是一整块刘姥姥进大观园，设计融合了传统与现代元素，展现出独特的艺术气息。前台工作人员的亲切问候和专业服务，让我从一开始就感受到了宾至如归的温暖。

房间内部的装饰同样令人印象深刻。家具布置考究，床品柔软舒适，保证了我每晚都能拥有高质量的睡眠。房间内的现代化设施一应俱全，高速的无线网络都极大地方便了我的工作和生活需求。

服务方面，广州花园酒店的每一位员工都展现出了高度的专业素养和热情周到。他们对客人的需求反应迅速，总是能够提供及时的帮助和解决方案，让我的住宿体验更加顺畅和愉快。特别是前台的Tony，处处能为客人考虑，很贴心。

总体来说，广州花园酒店以其优越的地理位置、典雅的装修风格、舒适的住宿环境、一流的餐饮服务以及专业的员工团队，为我提供了一次卓越的住宿体验。无论是商务出行还是休闲度假，我都会毫不犹豫地向朋友和家人推荐这家酒店，并期待在未来有机会再次入住。', '2024-08-10', 5, '[''交通便利性'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230p12000f2iidikE647_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000f2innvyFAE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000f2if60s30A7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000f2imi8r4499_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000f2i8g3wC61A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000f2icmiq4D81_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000f2if60uED83_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000f2iks497A36_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000f2iogdn19B1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次很庆幸定了花园酒店，不愧是白金五星 各方面品质在线，出行便利，下次来还会选择', '这次很庆幸定了花园酒店，不愧是白金五星 各方面品质在线，出行便利，下次来还会选择花园', '2024-09-12', 5, '[''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230r12000fixlsl6C503_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000fixa5tl3DD3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000fixvqlw3E05_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务很好，地理位置优越。', '酒店服务很好，地理位置优越。', '2024-11-06', 4, '[''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0232b12000gjag89t323D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000gj9zbky492D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000gja72di5473_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO 